// ===== parts: “muchas líneas” como los blancos (1 path por cada M) =====
export const EXCLUDE_PARTS = splitByMoveTo(EXCLUDE_D).map((subD, idx) => ({
  id: `Exclude_${idx}`,
  d: subD,
}));

// ===== deterministic direction per part =====
function hash01(str) {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  // 0..1
  return (h >>> 0) / 4294967295;
}

function getPartVector(id, idx) {
  // 3 valores 0..1 (repartidos) para ángulo, radio, rotación
  const a = hash01(id + "|a");
  const b = hash01(id + "|b");
  const c = hash01(id + "|c");

  // ángulo (distribución completa)
  const theta = a * Math.PI * 2;

  // radio: preferí algo más fuerte al principio (1..0.35)
  const r = 0.35 + (1 - b) * 0.65;

  // rotación: alterna signo y varía
  const sign = idx % 2 === 0 ? 1 : -1;
  const rot = sign * (6 + c * 18); // 6..24 grados

  return { theta, r, rot };
}

export function ExcludeScatterAssemble({
  factor,
  excludeParts = EXCLUDE_PARTS,
  scatterPx = 14,
  rotateDeg = 18, // lo mantenemos como “máximo” si querés
  origin = "85.5px 78px",

  delay = 0.6,
  dur = 0.25,

  // stagger
  stagger = 0.012,      // separación entre piezas
  staggerMax = 0.18,    // tope para no alargar infinito

  // blur/opacity extra
  startBlur = 4,        // px
  startOpacity = 0,     // al inicio del armado

  stroke = "#DEBB35",
  strokeWidth = 0.9,
  opacity = 1,
}) {
  if (!factor || !excludeParts?.length) return null;

  // precomputo de vectores por parte (determinista)
  const vectors = useMemo(
    () =>
      excludeParts.map((p, idx) => {
        const v = getPartVector(p.id, idx);
        return {
          ...v,
          // offsets finales (cada pieza en dirección distinta)
          dx: Math.cos(v.theta) * scatterPx * v.r,
          dy: Math.sin(v.theta) * scatterPx * v.r,
          // rotación por pieza
          drot: (v.rot / 24) * rotateDeg, // escala con rotateDeg
        };
      }),
    [excludeParts, scatterPx, rotateDeg]
  );

  return (
    <>
      {excludeParts.map((p, idx) => {
        const st = Math.min(idx * stagger, staggerMax);

        // factor tardío + stagger por pieza
        const localFactor = useTransform(factor, (t) => {
          const td = (t - (delay + st)) / dur;
          return td < 0 ? 0 : td > 1 ? 1 : td;
        });

        // blur: empieza borroso y se “enfoca”
        const blur = useTransform(localFactor, (v) => (1 - v) * startBlur);

        // opacity: arranca bajo y sube
        const op = useTransform(localFactor, (v) =>
          startOpacity + v * (opacity - startOpacity)
        );

        const v = vectors[idx];

        return (
          <Piece
            key={p.id}
            i={idx + 999}
            factor={localFactor}
            origin={origin}
            // 👇 NUEVO: offsets/rot por parte
            scatterX={v.dx}
            scatterY={v.dy}
            rotateBy={v.drot}
          >
            <path
              d={p.d}
              fill="none"
              stroke={stroke}
              strokeWidth={strokeWidth}
              opacity={op}
              style={{ filter: `blur(${blur.get?.() ?? 0}px)` }}
              vectorEffect="non-scaling-stroke"
              strokeLinejoin="round"
              strokeLinecap="round"
              strokeMiterlimit="2"
            />
          </Piece>
        );
      })}
    </>
  );
}